/* ============================================
   BASE STYLES
   ============================================ */

body {
  margin: 0;
  padding: 0;
  min-height: 100dvh;
  width: 100dvw;
  display: flex;
  flex-direction: column;
  gap: 100px;
  justify-content: center;
  align-items: center;
  background: white;
}

/* ============================================
   KEYFRAME ANIMATIONS
   ============================================ */

/* Sine wave animations for organic motion */
@keyframes s1 {
  to {
    --s1: 360deg;
  }
}
@keyframes s2 {
  to {
    --s2: 360deg;
  }
}
@keyframes s3 {
  to {
    --s3: 360deg;
  }
}
@keyframes rotation {
  to {
    --rotation: 360deg;
  }
}

/* Mesh gradient color animation */
@keyframes mesh-gradient {
  0% {
    --mesh-x-0: 85%;
    --mesh-y-0: 80%;
    --mesh-c-1: hsla(220, 100%, 82%, 1);
    --mesh-x-1: 60%;
    --mesh-y-1: 24%;
    --mesh-x-2: 13%;
    --mesh-y-2: 82%;
    --mesh-x-3: 24%;
    --mesh-y-3: 7%;
  }
  100% {
    --mesh-x-0: 31%;
    --mesh-y-0: 94%;
    --mesh-c-1: hsla(220, 82%, 95%, 1);
    --mesh-x-1: 2%;
    --mesh-y-1: 25%;
    --mesh-x-2: 98%;
    --mesh-y-2: 20%;
    --mesh-x-3: 95%;
    --mesh-y-3: 92%;
  }
}

/* Film grain jitter effect */
@keyframes grain-jitter {
